import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Getting Started with Voice Logging","description":"","frontmatter":{},"headers":[],"relativePath":"voice-logging/getting-started.md","filePath":"voice-logging/getting-started.md"}'),r={name:"voice-logging/getting-started.md"};function n(s,e,l,g,d,c){return t(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started-with-voice-logging" tabindex="-1">Getting Started with Voice Logging <a class="header-anchor" href="#getting-started-with-voice-logging" aria-label="Permalink to &quot;Getting Started with Voice Logging&quot;">​</a></h1><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><p>Voice logging requires a paid subscription (Player, Coach, or Organization). Free accounts do not have access to voice logging.</p><p><strong>Supported browsers:</strong></p><ul><li>Android: Chrome (recommended)</li><li>iOS: Safari</li><li>Desktop: Chrome or Edge</li></ul><p>Firefox has limited voice logging support and is not recommended.</p><h2 id="first-time-setup" tabindex="-1">First Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First Time Setup&quot;">​</a></h2><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><ol><li>Install Diamond Analytics to your home screen via Chrome</li><li>Go to <strong>Settings → General Management → Keyboard list and default</strong></li><li>Set <strong>Google Voice Typing</strong> as your default input method</li><li>Return to Diamond Analytics — the microphone is now always one tap away in the keyboard</li></ol><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><p>No extra setup required. Safari handles voice input natively.</p><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to &quot;Desktop&quot;">​</a></h3><p>No setup required. Click the microphone button and speak.</p><h2 id="accessing-voice-logging-during-a-game" tabindex="-1">Accessing Voice Logging During a Game <a class="header-anchor" href="#accessing-voice-logging-during-a-game" aria-label="Permalink to &quot;Accessing Voice Logging During a Game&quot;">​</a></h2><ol><li>Start a game session from the dashboard</li><li>From the <strong>Game Hub</strong> tap <strong>Voice Log</strong></li><li>The voice logging interface opens</li></ol><p>On mobile the keyboard appears automatically. Tap the microphone icon on the keyboard, speak your play description, then tap the arrow/send button.</p><p>On desktop tap the microphone button, speak, and the recording stops automatically.</p><h2 id="review-and-confirm" tabindex="-1">Review and Confirm <a class="header-anchor" href="#review-and-confirm" aria-label="Permalink to &quot;Review and Confirm&quot;">​</a></h2><p>After speaking a <strong>confirmation card</strong> appears showing:</p><ul><li>The logger type the AI identified (Pitching, Hitting, Fielding, or Baserunning)</li><li>The player matched from your roster</li><li>The specific fields parsed from your description</li><li>Zone pickers to visually confirm or correct location data</li></ul><p>Tap <strong>Confirm and Save</strong> to log the play. Tap <strong>Edit</strong> to open the manual logger with all fields pre-filled. Tap <strong>Try Again</strong> to re-speak the play.</p>',21)])])}const u=i(r,[["render",n]]);export{p as __pageData,u as default};
